// generar_251_medicamentos_multi_seleccion.js
// CHIQUI Entre Señales — Registro diario: multi-selección de medicamentos
//
// Mejora sobre el 249/250: el mini-modal de medicamentos ahora permite
// marcar VARIOS medicamentos en una sola acción. Si el usuario tiene 2
// (o más) tratamientos activos y se los dio ambos hoy, ya no tiene que
// abrir el modal dos veces.
//
// Detalles del cambio:
//
// 1) Radio-buttons → CHECKBOXES cuadrados. El cambio visual comunica
//    "puedes elegir varios" en el lenguaje universal de UI.
//
// 2) PRE-SELECCIÓN de TODOS al abrir. Asunción amable: si tiene varios
//    tratamientos activos, lo más común es que le haya dado todos hoy.
//    El usuario solo desmarca los que NO le dio, minimizando toques.
//
// 3) Texto adaptativo:
//    - Encabezado: "¿Le diste este medicamento hoy?" (1 activo)
//      vs "Marca los que le diste hoy (puedes elegir varios)." (2+).
//    - Botón: "Confirmar toma de hoy" (1 elegido)
//      vs "Confirmar 2 tomas de hoy" (varios)
//      vs "Marca al menos uno" (ninguno, disabled).
//
// 4) Guardado en un solo upsert: array de filas, no llamadas repetidas.
//    UNIQUE(medicamento_id, fecha) sigue previniendo tomas repetidas
//    si el usuario ya había marcado alguno hoy y vuelve a confirmar.
//
// Solo reescribe app/registro-diario/page.tsx. No hay SQL.
//
// Uso:
//   node generar_251_medicamentos_multi_seleccion.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/registro-diario/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
